  "templates/style.css": "@import url('https://fonts.googleapis.com/css2?family=Poly:ital@0;1&display=swap');\n\n:root {\n  /* Colors */\n\n\n  --foreground: #282828;\n  --background: #FFFDF7;\n  --highlight: darkred;\n  --secondary: #262626;\n  --trinary: #252525;\n  --neutral-1: #808080;\n  --neutral-2: #cdcdcd;\n  --neutral-3: #f5f5f5;\n\n  --bg-color: var(--background);\n  --fg-color: var(--foreground);\n  --neutral-background-color: #efefef;\n  --highlight-color: var(--highlight);\n  --neutral-color: var(--neutral-2);\n\n\n  --color-border: var(--neutral-color);\n  --font-family: \"Poly\", serif;\n\n  /* SVG pattern fills */\n  --pattern-fill: var(--bg-color);\n  --pattern-stroke: var(--fg-color);\n\n  /* SVG data elements (bars, circles, paths, slices) */\n  --data-element-stroke: var(--fg-color);\n  --data-element-stroke-width: 1;\n\n  /* SVG axes */\n  --axis-stroke: #999;\n  --axis-stroke-width: 1;\n\n  /* SVG labels */\n  --label-fill: var(--fg-color);\n  --label-font-size: 10px;\n  --label-font-family:  \"Poly\", serif;\n;\n}\n\n*,\n*::before,\n*::after {\n  box-sizing: border-box;\n  margin: 0;\n  padding: 0;\n}\n\nbody {\n  font-family: var(--font-family);\n  line-height: 1.6;\n  color: var(--fg-color);\n  background: var(--bg-color);\n  max-width: 860px;\n  margin: 0 auto;\n  padding: 0 1.5rem;\n}\n\n\na {\n  color: var(--highlight);\n}\n\nheader {\n  border-bottom: 1px solid #ddd;\n  padding: 1rem 0;\n  margin-bottom: 2rem;\n}\n\nheader nav {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  flex-wrap: wrap;\n  gap: 0.5rem;\n}\n\n.site-title {\n  font-size: 1.25rem;\n  font-weight: 700;\n  color: var(--fg-color);\n  text-decoration: none;\n}\n\n.logo {\n  width: 4em;\n  height: 4em;\n}\n\n.nav-links {\n  display: flex;\n  gap: 1.25rem;\n}\n\n.nav-links a {\n  color: var(--highlight-color);\n  text-decoration: none;\n  font-size: 0.9rem;\n}\n\n.nav-links a:hover {\n  color: var(--highlight-color);\n}\n\nmain {\n  min-height: 60vh;\n  padding-bottom: 2rem;\n}\n\nh1, h2, h3, h4 {\n  margin-top: 1.5em;\n  margin-bottom: 0.5em;\n  line-height: 1.3;\n}\n\nh1 { font-size: 2rem; }\nh2 { font-size: 1.5rem; }\nh3 { font-size: 1.2rem; }\n\np {\n  color: var(--fg-color);\n  margin-bottom: 1em;\n}\n\narticle {\n  padding-bottom: 2rem;\n}\n\n.post-meta {\n  color: var(--neutral);\n  font-size: 0.9rem;\n  margin-bottom: 1.5rem;\n}\n\n.post-meta time {\n  font-style: italic;\n}\n\nsvg {\n  max-width: 100%;\n  height: auto;\n  display: block;\n  margin: 1.5rem auto;\n  background: var(--bg-color);\n}\n\n.data-element {\n  stroke: var(--data-element-stroke);\n  stroke-width: var(--data-element-stroke-width);\n}\n\n.axis {\n  stroke: var(--axis-stroke);\n  stroke-width: var(--axis-stroke-width);\n}\n\n.label {\n  fill: var(--label-fill);\n  font-size: var(--label-font-size);\n  font-family: var(--label-font-family);\n  font-weight: 400;\n}\n\n.chart-error {\n  border: 2px solid #d00;\n  padding: 10px;\n  margin: 10px 0;\n  background: #fee;\n}\n\npre.code {\n  background: var(--neutral-background-color);\n  border: 1px solid rgba(0,0,0,0.1);\n  border-radius: 4px;\n  padding: 1rem;\n  overflow-x: auto;\n  font-size: 0.85rem;\n  margin: 1rem 0;\n}\n\ncode {\n  font-family: monospace;\n  font-size: 0.85em;\n  background: var(--neutral-background-color);\n  padding: 0.15em 0.3em;\n  border-radius: 3px;\n}\n\npre.code code {\n  background: none;\n  padding: 0;\n}\n\n.keyword { color: var(--highlight); font-weight: 600; }\n.string  { color: var(--secondary); }\n.comment { color: var(--neutral-1); font-style: italic; }\n.literal { color: var(--trinary); }\n\nul, ol {\n  margin: 0.5em 0 1em 1.5em;\n}\n\nli {\n  margin-bottom: 0.3em;\n}\n\n.post-list {\n  list-style: none;\n  margin-left: 0;\n  padding: 0;\n}\n\n.post-list li {\n  border-bottom: 1px solid #eee;\n  padding: 1rem 0;\n}\n\n.post-list li:last-child {\n  border-bottom: none;\n}\n\n.post-list h3 {\n  margin-top: 0;\n  margin-bottom: 0.25em;\n}\n\n.post-list p {\n  font-size: 0.9rem;\n  margin-bottom: 0.25em;\n}\n\n.post-list small {\n  color: var(--neutral-1);\n  font-size: 0.8rem;\n}\n\na.tag {\n  padding: 0.5em;\n  background-color: var(--neutral-background-color);\n  color: var(--highlight);\n  text-decoration: none;\n}\n\n.tags-list {\n  list-style: none;\n  margin-left: 0;\n  padding: 0;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.5rem;\n  line-height: 3;\n}\n\n.tags-list li a {\n  display: inline-block;\n  background: var(--neutral-background-color);\n  padding: 0.3rem 0.75rem;\n  border-radius: 3px;\n  text-decoration: none;\n  color: var(--highlight-color);\n  font-size: 0.9rem;\n}\n\n.tags-list li a:hover {\n  background: #ddd;\n}\n\n.pagination {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 1.5rem;\n  margin: 2rem 0;\n  padding-top: 1rem;\n  border-top: 1px solid #eee;\n}\n\n.pagination span {\n  color: var(--neutral-1);\n  font-size: 0.9rem;\n}\n\n.site-description {\n  font-size: 1rem;\n  margin-bottom: 2rem;\n}\n\n#search-input,\n#tag-search {\n  width: 100%;\n  padding: 0.75rem;\n  font-size: 1rem;\n  border: 1px solid #ccc;\n  border-radius: 4px;\n  margin-bottom: 1rem;\n}\n\n#search-input:focus,\n#tag-search:focus {\n  outline: none;\n  border-color: var(--neutral-1);\n  box-shadow: 0 0 0 2px rgba(0, 85, 170, 0.15);\n}\n\n.search-results {\n  list-style: none;\n  margin-left: 0;\n  padding: 0;\n}\n\n.search-results li {\n  border-bottom: 1px solid #eee;\n  padding: 0.75rem 0;\n}\n\ntable {\n  border-collapse: collapse;\n  width: 100%;\n  margin: 1rem 0;\n}\n\nth, td {\n  border: 1px solid #ddd;\n  padding: 0.5rem 0.75rem;\n  text-align: left;\n}\n\nth {\n  background: var(--bg-color);\n  font-weight: 600;\n}\n\nblockquote {\n  border-left: 3px solid #ccc;\n  margin: 1rem 0;\n  padding: 0.5rem 1rem;\n  color: var(--neutral-1);\n}\n\nabbr {\n  text-decoration: underline dotted;\n  cursor: help;\n}\n\nfigure.chart-figure {\n  margin: 1.5rem 0;\n}\n\n.chart-figcaption {\n  padding: 0.75rem;\n  border-top: none;\n  font-size: 0.85rem;\n  text-align: center;\n}\n\n.chart-figcaption table {\n  margin: 0;\n  font-size: 0.9rem;\n}\n\n.chart-figcaption td:first-child {\n  width: 30%;\n}\n\nfooter {\n  border-top: 1px solid #ddd;\n  padding: 1rem 0;\n  margin-top: 2rem;\n  color: var(--fg-color);\n  font-size: 0.85rem;\n  text-align: center;\n}\n\n@view-transition {\n  navigation: auto;\n}\n\n::view-transition-old(root),\n::view-transition-new(root) {\n  animation-duration: 0.3s;\n}\n\n::view-transition-old(root) {\n  animation-name: fade-out;\n}\n\n::view-transition-new(root) {\n  animation-name: fade-in;\n}\n\n@keyframes fade-out {\n  to {\n    opacity: 0;\n  }\n}\n\n@keyframes fade-in {\n  from {\n    opacity: 0;\n  }\n}",
